import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Box,
  Typography,
  Grid,
  TextField,
  Accordion,
  AccordionSummary,
  AccordionDetails,
  IconButton,
  Tooltip,
  useMediaQuery,
} from '@mui/material';
import {
  ExpandMore as ExpandMoreIcon,
  Palette as PaletteIcon,
  Refresh as RefreshIcon,
} from '@mui/icons-material';
import { useColorContext } from '../theme/ColorContext';

// Utility functions for color conversion
const rgbaToHex = (rgba) => {
  if (!rgba || typeof rgba !== 'string') return '#000000';
  
  // If it's already a hex color, return it
  if (rgba.startsWith('#')) return rgba;
  
  // Handle rgba format
  const rgbaMatch = rgba.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)(?:,\s*([\d.]+))?\)/);
  if (rgbaMatch) {
    const r = parseInt(rgbaMatch[1]);
    const g = parseInt(rgbaMatch[2]);
    const b = parseInt(rgbaMatch[3]);
    
    // Convert to hex
    const hex = '#' + 
      Math.round(r).toString(16).padStart(2, '0') +
      Math.round(g).toString(16).padStart(2, '0') +
      Math.round(b).toString(16).padStart(2, '0');
    
    return hex;
  }
  
  return '#000000';
};

const hexToRgba = (hex, alpha = 1) => {
  if (!hex || !hex.startsWith('#')) return `rgba(0, 0, 0, ${alpha})`;
  
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

const ColorPicker = ({ open, onClose }) => {
  const { customColors, updateColor } = useColorContext();
  const [localColors, setLocalColors] = useState(customColors);
  const isTouch = useMediaQuery('(pointer: coarse)');

  // Update local colors when dialog opens to ensure we have current colors
  useEffect(() => {
    if (open) {
      // Always use the current colors from context, not saved localStorage values
      setLocalColors(customColors);
    }
  }, [open, customColors]);

  const handleColorChange = (category, subcategory, property, value) => {
    setLocalColors(prev => {
      const newColors = { ...prev };
      
      if (subcategory) {
        if (property) {
          newColors[category][subcategory][property] = value;
        } else {
          newColors[category][subcategory] = value;
        }
      } else {
        if (property) {
          newColors[category][property] = value;
        } else {
          newColors[category] = value;
        }
      }
      
      return newColors;
    });

    // Apply change immediately
    updateColor(category, subcategory, property, value);
  };

  const handleSave = () => {
    // All changes are already applied, just close the dialog
    onClose();
  };

  const handleReset = () => {
    // Define default colors
    const defaultColors = {
      primary: {
        main: '#00bcd4',
        light: '#005577',
      },
      secondary: {
        main: '#8892b0',
        light: '#222b3a',
      },
      background: {
        dark: '#0a192f',
        light: '#f5f7fa',
        paper: {
          dark: '#112240',
          light: '#ffffff',
        },
      },
      text: {
        tertiary: {
          dark: '#8892b0',
          light: '#8892b0',
        },
        quadray: {
          dark: '#8892b0',
          light: '#8892b0',
        },
      },
      utility: {
        overlay: {
          dark: '#ffffff',
          light: '#ffffff',
        },
        shadow: {
          dark: '#000000',
          light: '#000000',
        },
        pdfBackground: '#222222',
      },
      scrollbar: {
        track: {
          dark: '#0a192f',
          light: '#f5f7fa',
        },
        thumb: {
          dark: '#00bcd4',
          light: '#005577',
        },
      },
      cursor: {
        primary: {
          dark: '#005577',
          light: '#005577',
        },
        accent: {
          dark: '#00bcd4',
          light: '#00bcd4',
        },
      },
    };
    
    // Update local state immediately
    setLocalColors(defaultColors);
    
    // Apply all changes to context immediately
    Object.keys(defaultColors).forEach(category => {
      const categoryData = defaultColors[category];
      if (typeof categoryData === 'object' && !Array.isArray(categoryData)) {
        Object.keys(categoryData).forEach(subcategory => {
          const subcategoryData = categoryData[subcategory];
          if (typeof subcategoryData === 'object' && !Array.isArray(subcategoryData)) {
            Object.keys(subcategoryData).forEach(property => {
              updateColor(category, subcategory, property, subcategoryData[property]);
            });
          } else {
            updateColor(category, subcategory, null, subcategoryData);
          }
        });
      } else {
        updateColor(category, null, null, categoryData);
      }
    });
  };

  const handleClose = () => {
    // Reset any unsaved changes by reloading from context
    setLocalColors(customColors);
    onClose();
  };

  const renderColorField = (category, subcategory, property, value, label) => {
    const fieldKey = `${category}-${subcategory || 'main'}-${property || 'main'}`;
    
    // Convert rgba to hex for display if needed
    const displayValue = rgbaToHex(value);
    const isRgba = value && value.includes('rgba');
    
    return (
      <Grid item xs={12} sm={6} md={6} key={fieldKey}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, flex: '0 0 auto' }}>
            <input
              type="color"
              value={displayValue}
              onChange={(e) => {
                const newValue = e.target.value;
                // If the original was rgba, convert back to rgba with original alpha
                if (isRgba) {
                  const alpha = value.match(/rgba?\([^)]*,\s*([\d.]+)\)/)?.[1] || '1';
                  const rgbaValue = hexToRgba(newValue, parseFloat(alpha));
                  handleColorChange(category, subcategory, property, rgbaValue);
                } else {
                  handleColorChange(category, subcategory, property, newValue);
                }
              }}
              style={{
                width: '40px',
                height: '40px',
                border: '2px solid #ddd',
                borderRadius: '4px',
                cursor: 'pointer',
                padding: 0,
                backgroundColor: value,
              }}
            />
            {isRgba && (
              <Tooltip title="This color uses transparency (rgba). The hex value shown is the solid color equivalent.">
                <Box
                  sx={{
                    width: 20,
                    height: 20,
                    borderRadius: '50%',
                    bgcolor: 'warning.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize: '12px',
                    color: 'white',
                    cursor: 'help',
                  }}
                >
                  α
                </Box>
              </Tooltip>
            )}
          </Box>
          <Box sx={{ flex: 1 }}>
            <TextField
              size="small"
              label={label}
              value={displayValue}
              onChange={(e) => {
                const newValue = e.target.value;
                // If the original was rgba, convert back to rgba with original alpha
                if (isRgba) {
                  const alpha = value.match(/rgba?\([^)]*,\s*([\d.]+)\)/)?.[1] || '1';
                  const rgbaValue = hexToRgba(newValue, parseFloat(alpha));
                  handleColorChange(category, subcategory, property, rgbaValue);
                } else {
                  handleColorChange(category, subcategory, property, newValue);
                }
              }}
              sx={{ width: '100%' }}
            />
          </Box>
        </Box>
      </Grid>
    );
  };

  const renderCategory = (category, data, title) => {
    // Map category names to human-readable labels
    const categoryLabels = {
      'primary': 'Text Colors',
      'secondary': 'Secondary Colors', 
      'background': 'Alternating Section Colors',
      'text': 'Text Colors',
      'utility': 'Utility Colors',
      'scrollbar': 'Scrollbar Colors',
      'cursor': 'Cursor Colors'
    };

    // Map property names to human-readable labels
    const propertyLabels = {
      'main': 'Dark Mode',
      'light': 'Light Mode',
      'dark': 'Dark Mode',
      'primary': 'Tertiary',
      'secondary': 'Quadray',
      'overlay': 'Overlay',
      'shadow': 'Shadow',
      'pdfBackground': 'PDF Background',
      'track': 'Track',
      'thumb': 'Thumb',
      'thumbHover': 'Thumb Hover',
      'accent': 'Accent'
    };

    // Special handling for combined text colors section
    if (category === 'primary') {
      return (
        <Accordion key={category} defaultExpanded>
          <AccordionSummary expandIcon={<ExpandMoreIcon />}>
            <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <PaletteIcon />
              Text Colors
            </Typography>
          </AccordionSummary>
          <AccordionDetails>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                  Primary
                </Typography>
                <Grid container spacing={2}>
                  {Object.entries(data).map(([key, value]) => 
                    renderColorField(
                      'primary',
                      null,
                      key,
                      value,
                      propertyLabels[key] || key.charAt(0).toUpperCase() + key.slice(1)
                    )
                  )}
                </Grid>
              </Grid>
              <Grid item xs={12}>
                <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                  Secondary
                </Typography>
                <Grid container spacing={2}>
                  {Object.entries(localColors.secondary).map(([key, value]) =>
                    renderColorField(
                      'secondary',
                      null,
                      key,
                      value,
                      propertyLabels[key] || key.charAt(0).toUpperCase() + key.slice(1)
                    )
                  )}
                </Grid>
              </Grid>
              <Grid item xs={12}>
                <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                  Tertiary
                </Typography>
                <Grid container spacing={2}>
                  {renderColorField(
                    'text',
                    'tertiary',
                    'dark',
                    localColors.text?.tertiary?.dark || localColors.text?.primary || '#8892b0',
                    'Dark Mode'
                  )}
                  {renderColorField(
                    'text',
                    'tertiary',
                    'light',
                    localColors.text?.tertiary?.light || localColors.text?.primary || '#8892b0',
                    'Light Mode'
                  )}
                </Grid>
              </Grid>
              <Grid item xs={12}>
                <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                  Quadray
                </Typography>
                <Grid container spacing={2}>
                  {renderColorField(
                    'text',
                    'quadray',
                    'dark',
                    localColors.text?.quadray?.dark || localColors.text?.secondary || '#8892b0',
                    'Dark Mode'
                  )}
                  {renderColorField(
                    'text',
                    'quadray',
                    'light',
                    localColors.text?.quadray?.light || localColors.text?.secondary || '#8892b0',
                    'Light Mode'
                  )}
                </Grid>
              </Grid>
            </Grid>
          </AccordionDetails>
        </Accordion>
      );
    }

    // Skip rendering secondary colors since they're included in the combined section
    if (category === 'secondary') {
      return null;
    }

    // Skip rendering text category since it's included in the combined section
    if (category === 'text') {
      return null;
    }

    // Special handling for utility category
    if (category === 'utility') {
      return (
        <Accordion key={category} defaultExpanded>
          <AccordionSummary expandIcon={<ExpandMoreIcon />}>
            <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <PaletteIcon />
              Utility Colors
            </Typography>
          </AccordionSummary>
          <AccordionDetails>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                  Overlay
                </Typography>
                <Grid container spacing={2}>
                  {renderColorField(
                    'utility',
                    'overlay',
                    'dark',
                    data.overlay?.dark || data.overlay || '#ffffff',
                    'Dark Mode'
                  )}
                  {renderColorField(
                    'utility',
                    'overlay',
                    'light',
                    data.overlay?.light || data.overlay || '#ffffff',
                    'Light Mode'
                  )}
                </Grid>
              </Grid>
              <Grid item xs={12}>
                <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                  Shadow
                </Typography>
                <Grid container spacing={2}>
                  {renderColorField(
                    'utility',
                    'shadow',
                    'dark',
                    data.shadow?.dark || data.shadow || '#000000',
                    'Dark Mode'
                  )}
                  {renderColorField(
                    'utility',
                    'shadow',
                    'light',
                    data.shadow?.light || data.shadow || '#000000',
                    'Light Mode'
                  )}
                </Grid>
              </Grid>
            </Grid>
          </AccordionDetails>
        </Accordion>
      );
    }

    // Special handling for cursor category
    if (category === 'cursor') {
      return (
        <Accordion key={category} defaultExpanded>
          <AccordionSummary expandIcon={<ExpandMoreIcon />}>
            <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <PaletteIcon />
              Cursor Colors
            </Typography>
          </AccordionSummary>
          <AccordionDetails>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                  Body Color
                </Typography>
                <Grid container spacing={2}>
                  {renderColorField(
                    'cursor',
                    'primary',
                    'dark',
                    data.primary?.dark || data.primary || '#005577',
                    'Dark Mode'
                  )}
                  {renderColorField(
                    'cursor',
                    'primary',
                    'light',
                    data.primary?.light || data.primary || '#005577',
                    'Light Mode'
                  )}
                </Grid>
              </Grid>
              <Grid item xs={12}>
                <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                  Accent
                </Typography>
                <Grid container spacing={2}>
                  {renderColorField(
                    'cursor',
                    'accent',
                    'dark',
                    data.accent?.dark || data.accent || '#00bcd4',
                    'Dark Mode'
                  )}
                  {renderColorField(
                    'cursor',
                    'accent',
                    'light',
                    data.accent?.light || data.accent || '#00bcd4',
                    'Light Mode'
                  )}
                </Grid>
              </Grid>
            </Grid>
          </AccordionDetails>
        </Accordion>
      );
    }

    // Special handling for scrollbar category
    if (category === 'scrollbar') {
      return (
        <Accordion key={category} defaultExpanded>
          <AccordionSummary expandIcon={<ExpandMoreIcon />}>
            <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <PaletteIcon />
              Scrollbar Colors
            </Typography>
          </AccordionSummary>
          <AccordionDetails>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                  Track
                </Typography>
                <Grid container spacing={2}>
                  {renderColorField(
                    'scrollbar',
                    'track',
                    'dark',
                    data.track?.dark || data.track || '#0a192f',
                    'Dark Mode'
                  )}
                  {renderColorField(
                    'scrollbar',
                    'track',
                    'light',
                    data.track?.light || data.track || '#f5f7fa',
                    'Light Mode'
                  )}
                </Grid>
              </Grid>
              <Grid item xs={12}>
                <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                  Thumb
                </Typography>
                <Grid container spacing={2}>
                  {renderColorField(
                    'scrollbar',
                    'thumb',
                    'dark',
                    data.thumb?.dark || data.thumb || '#00bcd4',
                    'Dark Mode'
                  )}
                  {renderColorField(
                    'scrollbar',
                    'thumb',
                    'light',
                    data.thumb?.light || data.thumb || '#005577',
                    'Light Mode'
                  )}
                </Grid>
              </Grid>
            </Grid>
          </AccordionDetails>
        </Accordion>
      );
    }

    const displayTitle = categoryLabels[category] || title;

    // Special handling for background category
    if (category === 'background') {
      return (
        <Accordion key={category} defaultExpanded>
          <AccordionSummary expandIcon={<ExpandMoreIcon />}>
            <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              <PaletteIcon />
              Alternating Section Colors
            </Typography>
          </AccordionSummary>
          <AccordionDetails>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                  Section 1
                </Typography>
                <Grid container spacing={2}>
                  {renderColorField(
                    category,
                    null,
                    'dark',
                    data.dark,
                    'Dark Mode'
                  )}
                  {renderColorField(
                    category,
                    null,
                    'light',
                    data.light,
                    'Light Mode'
                  )}
                </Grid>
              </Grid>
              <Grid item xs={12}>
                <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                  Section 2
                </Typography>
                <Grid container spacing={2}>
                  {renderColorField(
                    category,
                    'paper',
                    'dark',
                    data.paper.dark,
                    'Dark Mode'
                  )}
                  {renderColorField(
                    category,
                    'paper',
                    'light',
                    data.paper.light,
                    'Light Mode'
                  )}
                </Grid>
              </Grid>
            </Grid>
          </AccordionDetails>
        </Accordion>
      );
    }

    // Default rendering for other categories
    return (
      <Accordion key={category} defaultExpanded>
        <AccordionSummary expandIcon={<ExpandMoreIcon />}>
          <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <PaletteIcon />
            {displayTitle}
          </Typography>
        </AccordionSummary>
        <AccordionDetails>
          <Grid container spacing={2}>
            {Object.keys(data).map(key => {
              const value = data[key];
              if (typeof value === 'object' && !Array.isArray(value)) {
                // Nested object (like background.paper)
                const subcategoryLabel = key === 'paper' ? 'Section Background' : key.charAt(0).toUpperCase() + key.slice(1);
                return (
                  <Grid item xs={12} key={key}>
                    <Typography variant="subtitle1" sx={{ mb: 1, fontWeight: 'bold' }}>
                      {subcategoryLabel}
                    </Typography>
                    <Grid container spacing={2}>
                      {Object.keys(value).map(subKey => {
                        const propertyLabel = propertyLabels[subKey] || subKey.charAt(0).toUpperCase() + subKey.slice(1);
                        return renderColorField(
                          category, 
                          key, 
                          subKey, 
                          value[subKey], 
                          propertyLabel
                        );
                      })}
                    </Grid>
                  </Grid>
                );
              } else {
                // Simple color value - skip PDF Background
                if (key === 'pdfBackground') {
                  return null;
                }
                const propertyLabel = propertyLabels[key] || key.charAt(0).toUpperCase() + key.slice(1);
                // Special case for cursor primary
                const finalLabel = (category === 'cursor' && key === 'primary') ? 'Body Color' : propertyLabel;
                return renderColorField(
                  category, 
                  null, 
                  key, 
                  value, 
                  finalLabel
                );
              }
            })}
          </Grid>
        </AccordionDetails>
      </Accordion>
    );
  };

  return (
    <Dialog 
      open={open} 
      onClose={handleClose}
      maxWidth="md"
      fullWidth
      PaperProps={{
        sx: {
          maxHeight: '80vh',
        }
      }}
    >
      <DialogTitle sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <Typography variant="h5" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <PaletteIcon />
          Customize Colors
        </Typography>
        <Tooltip title="Reset to Default Colors">
          <IconButton onClick={handleReset} color="warning">
            <RefreshIcon />
          </IconButton>
        </Tooltip>
      </DialogTitle>
      
      <DialogContent>
        <Box sx={{ mb: 2 }}>
          <Typography variant="body2" color="text.secondary">
            Click on any color swatch to open the color picker, or type a hex value directly.
            Changes are applied immediately as you type or pick colors.
          </Typography>
        </Box>
        
        {renderCategory('primary', localColors.primary, 'Primary Colors')}
        {renderCategory('secondary', localColors.secondary, 'Secondary Colors')}
        {renderCategory('background', localColors.background, 'Background Colors')}
        {renderCategory('text', localColors.text, 'Text Colors')}
        {renderCategory('utility', localColors.utility, 'Utility Colors')}
        {renderCategory('scrollbar', localColors.scrollbar, 'Scrollbar Colors')}
        {!isTouch && renderCategory('cursor', localColors.cursor, 'Cursor Colors')}
      </DialogContent>
      
      <DialogActions>
        <Button onClick={handleClose}>Cancel</Button>
        <Button onClick={handleSave} variant="contained" color="primary">
          Done
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default ColorPicker; 